import{_ as t,o,c as r,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Codebase Review","description":"","frontmatter":{},"headers":[],"relativePath":"codebase-review-opencode.md","filePath":"codebase-review-opencode.md"}'),i={name:"codebase-review-opencode.md"};function a(n,e,c,d,l,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="codebase-review" tabindex="-1">Codebase Review <a class="header-anchor" href="#codebase-review" aria-label="Permalink to &quot;Codebase Review&quot;">​</a></h1><p>Review date: 2026-06-18 By Open Code (DeepSeek V4 Flash)</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Sovereign is an exceptionally well-engineered codebase. The architecture is the product of careful RFC-driven design; the documentation is comprehensive and kept honest by parity tests; the security posture (strict CSP, no default secrets, layered session verification) is production-quality.</p><p>The main gaps are in testing (no integration/E2E coverage, untested platform plugins) and middlegrowth refactoring opportunities in the middleware and generate script.</p><h2 id="improvement-points-priority-order" tabindex="-1">Improvement points (priority order) <a class="header-anchor" href="#improvement-points-priority-order" aria-label="Permalink to &quot;Improvement points (priority order)&quot;">​</a></h2><h3 id="_1-write-an-integration-smoke-test" tabindex="-1">1. Write an integration smoke test <a class="header-anchor" href="#_1-write-an-integration-smoke-test" aria-label="Permalink to &quot;1. Write an integration smoke test&quot;">​</a></h3><p><code>__tests__/integration/</code> and <code>__tests__/e2e/</code> exist as scaffolds (<code>--passWithNoTests</code>) but contain no real tests. A single smoke test covering register → login → verify launcher loads would catch middleware regressions, session-verify issues, plugin composition failures, and CSP blocking in one go. The infra (Vitest, Docker Compose) is all in place.</p><p><strong>Files:</strong> <code>__tests__/integration/</code>, <code>__tests__/e2e/</code></p><h3 id="_2-add-tests-for-the-three-platform-plugins" tabindex="-1">2. Add tests for the three platform plugins <a class="header-anchor" href="#_2-add-tests-for-the-three-platform-plugins" aria-label="Permalink to &quot;2. Add tests for the three platform plugins&quot;">​</a></h3><p>None of Console, Launcher, or Account have <code>__tests__/</code> directories despite <code>vitest.config.ts</code> including <code>plugins/**</code>. The Account plugin&#39;s display-name and password-change actions, and Console&#39;s plugin-toggle route are the highest value targets.</p><p><strong>Files:</strong> <code>plugins/account/</code>, <code>plugins/console/</code>, <code>plugins/launcher/</code></p><h3 id="_3-refactor-middleware-ts" tabindex="-1">3. Refactor <code>middleware.ts</code> <a class="header-anchor" href="#_3-refactor-middleware-ts" aria-label="Permalink to &quot;3. Refactor `middleware.ts`&quot;">​</a></h3><p>The single <code>middleware()</code> function at <code>runtime/middleware.ts:121</code> handles CSP, public API routing, session verification (local + fallback), plugin route protection, root-plugin rewrite, and header injection. It spans ~100 lines with deeply nested branches. The <code>applyCsp</code> and <code>withCookies</code> closures are passed around 5+ response construction sites, making the flow hard to follow.</p><p>Extract the response-builder helpers into their own module and consider splitting the three main middleware responsibilities (CSP, auth, plugin routing) into composable functions.</p><p><strong>Files:</strong> <code>runtime/middleware.ts</code></p><h3 id="_4-refactor-scripts-generate-registry-ts" tabindex="-1">4. Refactor <code>scripts/generate-registry.ts</code> <a class="header-anchor" href="#_4-refactor-scripts-generate-registry-ts" aria-label="Permalink to &quot;4. Refactor `scripts/generate-registry.ts`&quot;">​</a></h3><p>The generate script handles manifest validation, compatibility checks, registry writing, and route copying for multiple shell modes (default, overlay, with minimal wired but failing aggressively). As more shell modes come online it will become unwieldy. Break it into smaller modules.</p><p><strong>Files:</strong> <code>scripts/generate-registry.ts</code></p><h3 id="_5-audit-csp-nonce-generation" tabindex="-1">5. Audit CSP nonce generation <a class="header-anchor" href="#_5-audit-csp-nonce-generation" aria-label="Permalink to &quot;5. Audit CSP nonce generation&quot;">​</a></h3><p><code>runtime/src/security.ts:16-22</code> uses <code>String.fromCharCode</code> + <code>btoa</code> for the per-request nonce. This works in practice on V8/SpiderMonkey/JSC but is technically incorrect for byte values &gt; 127 — <code>String.fromCharCode</code> followed by <code>btoa</code> is not a correct base64 encoding of arbitrary bytes across all engines. Consider <code>crypto.randomUUID()</code> or a typed <code>Uint8Array</code> → hex encoding.</p><p><strong>Files:</strong> <code>runtime/src/security.ts</code></p><h3 id="_6-add-typescript-project-references" tabindex="-1">6. Add TypeScript project references <a class="header-anchor" href="#_6-add-typescript-project-references" aria-label="Permalink to &quot;6. Add TypeScript project references&quot;">​</a></h3><p>With 17+ packages/apps, <code>pnpm typecheck</code> runs via Turbo but without project references (<code>composite: true</code> + <code>references</code> in tsconfig) the type checker processes the entire dependency graph on every invocation. Project references would enable incremental caching and faster typechecking as the codebase grows.</p><p><strong>Files:</strong> <code>packages/tsconfig/</code>, individual <code>tsconfig.json</code> files</p><h3 id="_7-test-the-cli-orchestration-layer" tabindex="-1">7. Test the CLI orchestration layer <a class="header-anchor" href="#_7-test-the-cli-orchestration-layer" aria-label="Permalink to &quot;7. Test the CLI orchestration layer&quot;">​</a></h3><p><code>bin/helpers.ts</code> is unit-tested, but <code>bin/sv.ts</code> (the CLI orchestration that shells out to pnpm/turbo) has no coverage. The orchestration layer contains process-management logic (mutual teardown in <code>sv serve</code>, command sequencing in <code>sv build</code>) that would benefit from smoke tests.</p><p><strong>Files:</strong> <code>bin/sv.ts</code>, <code>bin/__tests__/</code></p><h3 id="_8-harden-the-vitest-test-discovery-glob" tabindex="-1">8. Harden the Vitest test-discovery glob <a class="header-anchor" href="#_8-harden-the-vitest-test-discovery-glob" aria-label="Permalink to &quot;8. Harden the Vitest test-discovery glob&quot;">​</a></h3><p>The <code>vitest.config.ts</code> <code>include</code> globs use <code>**/__tests__/**/*.test.{ts,tsx}</code> which relies on &quot;anchoring&quot; to avoid generated plugin copies under <code>runtime/app/(plugins)</code>. An explicit exclusion list would be more robust against future directory restructuring.</p><p><strong>Files:</strong> <code>vitest.config.ts</code></p><h3 id="_9-note-middleware-db-fetch-pattern-is-correct-but-worth-monitoring" tabindex="-1">9. Note: middleware DB-fetch pattern is correct but worth monitoring <a class="header-anchor" href="#_9-note-middleware-db-fetch-pattern-is-correct-but-worth-monitoring" aria-label="Permalink to &quot;9. Note: middleware DB-fetch pattern is correct but worth monitoring&quot;">​</a></h3><p>The middleware fetches disabled plugin IDs and the root plugin prefix from <code>localhost:3000</code> Node API routes (Edge can&#39;t open SQLite). This adds two <code>fetch()</code> calls per matching request. Fine for v1 scale but worth a stale-while-revalidate or in-memory cache strategy if the plugin count grows significantly.</p><p><strong>Files:</strong> <code>runtime/middleware.ts:31-61</code></p><h3 id="_10-note-dual-write-invite-only-toggle-has-a-desync-surface" tabindex="-1">10. Note: dual-write invite-only toggle has a desync surface <a class="header-anchor" href="#_10-note-dual-write-invite-only-toggle-has-a-desync-surface" aria-label="Permalink to &quot;10. Note: dual-write invite-only toggle has a desync surface&quot;">​</a></h3><p>The Console toggle writes to both <code>platform_settings</code> and <code>auth_settings</code>, but registration reads only the auth copy. If the two databases desync (e.g. a restore of one but not the other), the toggle UI could show one state while enforcement uses another. Low risk for v1 single-tenant but worth documenting in operations runbooks.</p><p><strong>Files:</strong> <code>plugins/console/</code>, <code>apps/auth/src/settings.ts</code></p>',37)])])}const g=t(i,[["render",a]]);export{u as __pageData,g as default};
